// lib/strategicAnalysis.ts
import { supabaseAdmin } from "./supabaseAdmin";
import OpenAI from "openai";

const deepseek = new OpenAI({
  apiKey: process.env.DEEPSEEK_API_KEY || '',
  baseURL: "https://api.deepseek.com",
});

export async function generateStrategicReport(articles: any[]) {
  const context = articles.map(a => 
    `[${a.neighborhood}] ${a.title}: ${a.summary}`
  ).join("\n");

  const prompt = `Eres un Analista de Inteligencia Estratégica. 
  Basado en estas noticias de las últimas 24h en Córdoba, genera un análisis técnico:
  1. Tendencia Criminal: ¿Hay un aumento en algún delito específico?
  2. Puntos Calientes (Hotspots): ¿Qué municipios presentan mayor criticidad?
  3. Recomendación de Seguridad: Acciones preventivas sugeridas.
  
  Noticias:
  ${context}`;

  try {
    const response = await deepseek.chat.completions.create({
      model: "deepseek-chat",
      messages: [
        { role: "system", content: "Genera reportes de inteligencia breves y tácticos." },
        { role: "user", content: prompt }
      ]
    });

    return response.choices[0].message.content;
  } catch (error) {
    console.error("Error en análisis estratégico:", error);
    return "No se pudo generar el análisis en este momento.";
  }
}